  // Auto-launch core tour on first access to the app - disabled in favor of premium voice walkthrough
  useEffect(() => {
    // Disabled to avoid double-tour overlaps. User can launch standard tour manually.
  }, []);

  // Synchronize layout tabs, view panels and speech for current walkthrough step
  useEffect(() => {
    if (isTourActive) {
      if (loading) return; // Don't speak empty values during loading
      const step = TOUR_STEPS[currentTourStep];
      if (step) {
        setActiveTab(step.tab);
        if ("subTab" in step && step.subTab) {
          setActiveSubTab(step.subTab as any);
        }
        let t: any;
        if ("modalTab" in step && step.modalTab) {
          t = setTimeout(() => {
            window.dispatchEvent(new CustomEvent('dafne_sync_modal_tab', { detail: step.modalTab }));
          }, 100);
        }
        
        // Speak if voice narration is enabled
        if (isTourVoiceEnabled) {
          if (lastSpokenTourTextRef.current !== step.speakText) {
            lastSpokenTourTextRef.current = step.speakText;
            sound.speak(
              step.speakText,
              () => setIsTourSpeaking(true),
              () => setIsTourSpeaking(false)
            );
          }
        } else {
          window.speechSynthesis.cancel();
          lastSpokenTourTextRef.current = "";
          setIsTourSpeaking(false);
        }
        return () => {
          if (t) clearTimeout(t);
        };
      }
    } else {
      if (lastSpokenTourTextRef.current !== "") {
        window.speechSynthesis.cancel();
        lastSpokenTourTextRef.current = "";
      }
      setIsTourSpeaking(false);
    }
  }, [currentTourStep, isTourActive, isTourVoiceEnabled, loading]);

  // Reactive completions for walkthrough tutorial steps
  useEffect(() => {
    if (activeTab === "cashflow") {
      completeTourTask("cashflow_explore");
    }
  }, [activeTab]);

  const prevTaxRateRef = useRef<number | undefined>(undefined);
  useEffect(() => {
    if (profile?.taxRate !== undefined) {
      if (prevTaxRateRef.current !== undefined && prevTaxRateRef.current !== profile.taxRate) {
        completeTourTask("tax_audit");
      }
      prevTaxRateRef.current = profile.taxRate;
    }
  }, [profile?.taxRate]);

  React.useEffect(() => {
    const params = new URLSearchParams(window.location.search);
    if (params.get("stripe_checkout") === "success") {
      // Clear URL params so page reload doesn't trigger it again
      const cleanUrl = window.location.pathname + window.location.hash;
      window.history.replaceState({}, document.title, cleanUrl);

      const planId = params.get("plan_id") || "pro";
      const formattedPrice = profile?.subscriptionPrice 
        ? profile.subscriptionPrice.toLocaleString("pt-BR", { minimumFractionDigits: 2 }) 
        : "99,99";
      
      const activate = async () => {
        if (isDemoMode) {
          showToast(`Investimento em Tecnologia de R$ ${formattedPrice}/mês ativo com sucesso via simulação do Stripe!`, "success");
        } else if (user) {
          try {
            await updateProfile({
              subscriptionPlan: planId as any,
              subscriptionStatus: "active"
            });
            showToast(`Investimento Tecnológico de R$ ${formattedPrice}/mês ativado com sucesso! Bem-vindo à Licença Tecnológica MaxPerformance Business.`, "success");
          } catch (err) {
            console.error(err);
            showToast("Erro ao confirmar investimento no banco de dados. Entre em contato com o suporte.", "error");
          }
        } else {
          showToast("Investimento concluído! Faça login para aproveitar os recursos de IA e cockpit.", "info");
        }
      };
      
      activate();
    } else if (params.get("stripe_checkout") === "cancel") {
      const cleanUrl = window.location.pathname + window.location.hash;
      window.history.replaceState({}, document.title, cleanUrl);
      showToast("O checkout do Stripe foi cancelado pelo usuário.", "warning");
    }
  }, [user, isDemoMode, loading, profile]);

