      pdfDoc.addBulletItem("•", "Economias de Escala: Forçar as centrais de compras agrupadas para obter maior margem bruta e mitigar pressões inflacionárias de insumos.");
      pdfDoc.addBulletItem("•", "Blindagem Fiscal: Auditar individualmente as faixas do Simples Nacional de cada CNPJ evitado transbordamento de alíquotas DAS.");

      // Salva o documento
      pdfDoc.doc.save(`Resumo_Financeiro_Visual_Diretoria_${format(new Date(), "dd_MM_yyyy")}.pdf`);
